import{_ as o,o as l,c as a,ag as i}from"./chunks/framework.CTpQozEL.js";const p=JSON.parse('{"title":"에이전트 루프","description":"에이전트 루프 생명주기, 스트림, 대기 시맨틱","frontmatter":{"title":"에이전트 루프","description":"에이전트 루프 생명주기, 스트림, 대기 시맨틱"},"headers":[],"relativePath":"concepts/agent-loop.md","filePath":"concepts/agent-loop.md","lastUpdated":null}'),t={name:"concepts/agent-loop.md"};function c(d,e,n,r,s,u){return l(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="에이전트-루프-openclaw" tabindex="-1">에이전트 루프 (OpenClaw) <a class="header-anchor" href="#에이전트-루프-openclaw" aria-label="Permalink to &quot;에이전트 루프 (OpenClaw)&quot;">​</a></h1><p>에이전트 루프는 에이전트의 완전한 &quot;실제&quot; 실행 흐름입니다: 입력 수신 → 컨텍스트 조립 → 모델 추론 → 도구 실행 → 스트리밍 응답 → 영속화. 이는 메시지를 액션과 최종 응답으로 변환하면서 세션 상태를 일관되게 유지하는 권위 있는 경로입니다.</p><p>OpenClaw에서 루프는 모델이 사고하고, 도구를 호출하고, 출력을 스트리밍하는 동안 생명주기 및 스트림 이벤트를 방출하는 세션당 단일 직렬화된 실행입니다. 이 문서에서는 이 루프가 엔드-투-엔드로 어떻게 연결되는지 설명합니다.</p><h2 id="진입점" tabindex="-1">진입점 <a class="header-anchor" href="#진입점" aria-label="Permalink to &quot;진입점&quot;">​</a></h2><ul><li>게이트웨이 RPC: <code>agent</code> 및 <code>agent.wait</code>.</li><li>CLI: <code>agent</code> 명령어.</li></ul><h2 id="작동-방식-상위-수준" tabindex="-1">작동 방식 (상위 수준) <a class="header-anchor" href="#작동-방식-상위-수준" aria-label="Permalink to &quot;작동 방식 (상위 수준)&quot;">​</a></h2><ol><li><code>agent</code> RPC는 파라미터를 검증하고, 세션(sessionKey/sessionId)을 확인하며, 세션 메타데이터를 영속화하고, 즉시 <code>{ runId, acceptedAt }</code>를 반환합니다.</li><li><code>agentCommand</code>가 에이전트를 실행합니다: <ul><li>모델 + 사고/상세 기본값을 확인합니다</li><li>스킬 스냅샷을 로드합니다</li><li><code>runEmbeddedPiAgent</code>(pi-agent-core 런타임)를 호출합니다</li><li>임베디드 루프가 생명주기 end/error를 방출하지 않으면 직접 방출합니다</li></ul></li><li><code>runEmbeddedPiAgent</code>: <ul><li>세션당 + 글로벌 큐를 통해 실행을 직렬화합니다</li><li>모델 + 인증 프로파일을 확인하고 pi 세션을 빌드합니다</li><li>pi 이벤트를 구독하고 어시스턴트/도구 델타를 스트리밍합니다</li><li>타임아웃을 강제 적용 → 초과 시 실행을 중단합니다</li><li>페이로드 + 사용 메타데이터를 반환합니다</li></ul></li><li><code>subscribeEmbeddedPiSession</code>은 pi-agent-core 이벤트를 OpenClaw <code>agent</code> 스트림으로 브리지합니다: <ul><li>도구 이벤트 =&gt; <code>stream: &quot;tool&quot;</code></li><li>어시스턴트 델타 =&gt; <code>stream: &quot;assistant&quot;</code></li><li>생명주기 이벤트 =&gt; <code>stream: &quot;lifecycle&quot;</code> (<code>phase: &quot;start&quot; | &quot;end&quot; | &quot;error&quot;</code>)</li></ul></li><li><code>agent.wait</code>는 <code>waitForAgentRun</code>을 사용합니다: <ul><li><code>runId</code>에 대한 <strong>생명주기 end/error</strong>를 기다립니다</li><li><code>{ status: ok|error|timeout, startedAt, endedAt, error? }</code>를 반환합니다</li></ul></li></ol><h2 id="큐잉-동시성" tabindex="-1">큐잉 + 동시성 <a class="header-anchor" href="#큐잉-동시성" aria-label="Permalink to &quot;큐잉 + 동시성&quot;">​</a></h2><ul><li>실행은 세션 키(세션 레인)마다 직렬화되며, 선택적으로 글로벌 레인을 통해 처리됩니다.</li><li>이는 도구/세션 경합을 방지하고 세션 히스토리를 일관되게 유지합니다.</li><li>메시징 채널은 이 레인 시스템에 피드되는 큐 모드(collect/steer/followup)를 선택할 수 있습니다. <a href="/openclaw-docs-ko/concepts/queue">커맨드 큐</a>를 참조하십시오.</li></ul><h2 id="세션-워크스페이스-준비" tabindex="-1">세션 + 워크스페이스 준비 <a class="header-anchor" href="#세션-워크스페이스-준비" aria-label="Permalink to &quot;세션 + 워크스페이스 준비&quot;">​</a></h2><ul><li>워크스페이스가 확인되고 생성됩니다; 샌드박스 실행은 샌드박스 워크스페이스 루트로 리다이렉트될 수 있습니다.</li><li>스킬이 로드(또는 스냅샷에서 재사용)되어 환경 변수와 프롬프트에 주입됩니다.</li><li>부트스트랩/컨텍스트 파일이 확인되어 시스템 프롬프트 보고서에 주입됩니다.</li><li>세션 쓰기 잠금이 획득됩니다; 스트리밍 전에 <code>SessionManager</code>가 열리고 준비됩니다.</li></ul><h2 id="프롬프트-조립-시스템-프롬프트" tabindex="-1">프롬프트 조립 + 시스템 프롬프트 <a class="header-anchor" href="#프롬프트-조립-시스템-프롬프트" aria-label="Permalink to &quot;프롬프트 조립 + 시스템 프롬프트&quot;">​</a></h2><ul><li>시스템 프롬프트는 OpenClaw의 기본 프롬프트, 스킬 프롬프트, 부트스트랩 컨텍스트, 실행별 오버라이드로 구성됩니다.</li><li>모델별 한도 및 컴팩션 예약 토큰이 적용됩니다.</li><li>모델이 보는 내용은 <a href="/openclaw-docs-ko/concepts/system-prompt">시스템 프롬프트</a>를 참조하십시오.</li></ul><h2 id="후크-포인트-인터셉트-가능한-위치" tabindex="-1">후크 포인트 (인터셉트 가능한 위치) <a class="header-anchor" href="#후크-포인트-인터셉트-가능한-위치" aria-label="Permalink to &quot;후크 포인트 (인터셉트 가능한 위치)&quot;">​</a></h2><p>OpenClaw에는 두 가지 후크 시스템이 있습니다:</p><ul><li><strong>내부 후크</strong> (게이트웨이 후크): 명령 및 생명주기 이벤트를 위한 이벤트 기반 스크립트.</li><li><strong>플러그인 후크</strong>: 에이전트/도구 생명주기 및 게이트웨이 파이프라인 내부의 확장 포인트.</li></ul><h3 id="내부-후크-게이트웨이-후크" tabindex="-1">내부 후크 (게이트웨이 후크) <a class="header-anchor" href="#내부-후크-게이트웨이-후크" aria-label="Permalink to &quot;내부 후크 (게이트웨이 후크)&quot;">​</a></h3><ul><li><strong><code>agent:bootstrap</code></strong>: 시스템 프롬프트가 확정되기 전에 부트스트랩 파일을 빌드하는 동안 실행됩니다. 부트스트랩 컨텍스트 파일을 추가/제거하는 데 사용합니다.</li><li><strong>커맨드 후크</strong>: <code>/new</code>, <code>/reset</code>, <code>/stop</code>, 기타 명령 이벤트 (후크 문서 참조).</li></ul><p>설정 및 예제는 <a href="/openclaw-docs-ko/automation/hooks">후크</a>를 참조하십시오.</p><h3 id="플러그인-후크-에이전트-게이트웨이-생명주기" tabindex="-1">플러그인 후크 (에이전트 + 게이트웨이 생명주기) <a class="header-anchor" href="#플러그인-후크-에이전트-게이트웨이-생명주기" aria-label="Permalink to &quot;플러그인 후크 (에이전트 + 게이트웨이 생명주기)&quot;">​</a></h3><p>이들은 에이전트 루프 또는 게이트웨이 파이프라인 내부에서 실행됩니다:</p><ul><li><strong><code>before_model_resolve</code></strong>: 세션 이전(<code>messages</code> 없음)에 실행되어 모델 확인 전에 프로바이더/모델을 결정론적으로 오버라이드합니다.</li><li><strong><code>before_prompt_build</code></strong>: 세션 로드 후(<code>messages</code> 포함) 실행되어 프롬프트 제출 전에 <code>prependContext</code>, <code>systemPrompt</code>, <code>prependSystemContext</code>, 또는 <code>appendSystemContext</code>를 주입합니다. 턴별 동적 텍스트에는 <code>prependContext</code>를, 시스템 프롬프트 영역에 안정적으로 위치해야 하는 지침에는 system-context 필드를 사용하십시오.</li><li><strong><code>before_agent_start</code></strong>: 두 단계 중 하나에서 실행될 수 있는 레거시 호환성 후크입니다; 위의 명시적 후크를 선호하십시오.</li><li><strong><code>before_agent_reply</code></strong>: 인라인 액션 이후, LLM 호출 전에 실행되어 플러그인이 턴을 점유하고 합성 응답을 반환하거나 턴을 완전히 침묵시킬 수 있습니다.</li><li><strong><code>agent_end</code></strong>: 완료 후 최종 메시지 목록과 실행 메타데이터를 검사합니다.</li><li><strong><code>before_compaction</code> / <code>after_compaction</code></strong>: 컴팩션 사이클을 관찰하거나 주석을 달 수 있습니다.</li><li><strong><code>before_tool_call</code> / <code>after_tool_call</code></strong>: 도구 파라미터/결과를 인터셉트합니다.</li><li><strong><code>before_install</code></strong>: 내장 스캔 결과를 검사하고 선택적으로 스킬 또는 플러그인 설치를 차단합니다.</li><li><strong><code>tool_result_persist</code></strong>: 도구 결과를 세션 트랜스크립트에 쓰기 전에 동기적으로 변환합니다.</li><li><strong><code>message_received</code> / <code>message_sending</code> / <code>message_sent</code></strong>: 인바운드 + 아웃바운드 메시지 후크.</li><li><strong><code>session_start</code> / <code>session_end</code></strong>: 세션 생명주기 경계.</li><li><strong><code>gateway_start</code> / <code>gateway_stop</code></strong>: 게이트웨이 생명주기 이벤트.</li></ul><p>아웃바운드/도구 가드에 대한 후크 결정 규칙:</p><ul><li><code>before_tool_call</code>: <code>{ block: true }</code>는 터미널이며 하위 우선순위 핸들러를 중단합니다.</li><li><code>before_tool_call</code>: <code>{ block: false }</code>는 no-op이며 이전 블록을 해제하지 않습니다.</li><li><code>before_install</code>: <code>{ block: true }</code>는 터미널이며 하위 우선순위 핸들러를 중단합니다.</li><li><code>before_install</code>: <code>{ block: false }</code>는 no-op이며 이전 블록을 해제하지 않습니다.</li><li><code>message_sending</code>: <code>{ cancel: true }</code>는 터미널이며 하위 우선순위 핸들러를 중단합니다.</li><li><code>message_sending</code>: <code>{ cancel: false }</code>는 no-op이며 이전 취소를 해제하지 않습니다.</li></ul><p>후크 API 및 등록 세부사항은 <a href="/openclaw-docs-ko/plugins/architecture#provider-runtime-hooks">플러그인 후크</a>를 참조하십시오.</p><h2 id="스트리밍-부분-응답" tabindex="-1">스트리밍 + 부분 응답 <a class="header-anchor" href="#스트리밍-부분-응답" aria-label="Permalink to &quot;스트리밍 + 부분 응답&quot;">​</a></h2><ul><li>어시스턴트 델타는 pi-agent-core에서 스트리밍되어 <code>assistant</code> 이벤트로 방출됩니다.</li><li>블록 스트리밍은 <code>text_end</code> 또는 <code>message_end</code>에서 부분 응답을 방출할 수 있습니다.</li><li>추론 스트리밍은 별도의 스트림 또는 블록 응답으로 방출될 수 있습니다.</li><li>청킹 및 블록 응답 동작은 <a href="/openclaw-docs-ko/concepts/streaming">스트리밍</a>을 참조하십시오.</li></ul><h2 id="도구-실행-메시징-도구" tabindex="-1">도구 실행 + 메시징 도구 <a class="header-anchor" href="#도구-실행-메시징-도구" aria-label="Permalink to &quot;도구 실행 + 메시징 도구&quot;">​</a></h2><ul><li>도구 시작/업데이트/종료 이벤트가 <code>tool</code> 스트림에서 방출됩니다.</li><li>도구 결과는 로깅/방출 전에 크기 및 이미지 페이로드에 대해 정제됩니다.</li><li>메시징 도구 전송은 중복 어시스턴트 확인을 억제하기 위해 추적됩니다.</li></ul><h2 id="응답-형성-억제" tabindex="-1">응답 형성 + 억제 <a class="header-anchor" href="#응답-형성-억제" aria-label="Permalink to &quot;응답 형성 + 억제&quot;">​</a></h2><ul><li>최종 페이로드는 다음으로 조립됩니다: <ul><li>어시스턴트 텍스트 (및 선택적 추론)</li><li>인라인 도구 요약 (verbose + 허용된 경우)</li><li>모델 오류 시 어시스턴트 오류 텍스트</li></ul></li><li>정확한 침묵 토큰 <code>NO_REPLY</code> / <code>no_reply</code>는 아웃고잉 페이로드에서 필터링됩니다.</li><li>메시징 도구 중복은 최종 페이로드 목록에서 제거됩니다.</li><li>렌더링 가능한 페이로드가 남지 않고 도구가 오류를 일으킨 경우, 폴백 도구 오류 응답이 방출됩니다 (메시징 도구가 이미 사용자에게 보이는 응답을 전송하지 않은 경우).</li></ul><h2 id="컴팩션-재시도" tabindex="-1">컴팩션 + 재시도 <a class="header-anchor" href="#컴팩션-재시도" aria-label="Permalink to &quot;컴팩션 + 재시도&quot;">​</a></h2><ul><li>자동 컴팩션은 <code>compaction</code> 스트림 이벤트를 방출하며 재시도를 트리거할 수 있습니다.</li><li>재시도 시, 중복 출력을 방지하기 위해 인메모리 버퍼와 도구 요약이 재설정됩니다.</li><li>컴팩션 파이프라인은 <a href="/openclaw-docs-ko/concepts/compaction">컴팩션</a>을 참조하십시오.</li></ul><h2 id="이벤트-스트림-현재" tabindex="-1">이벤트 스트림 (현재) <a class="header-anchor" href="#이벤트-스트림-현재" aria-label="Permalink to &quot;이벤트 스트림 (현재)&quot;">​</a></h2><ul><li><code>lifecycle</code>: <code>subscribeEmbeddedPiSession</code>에 의해 방출됨 (그리고 <code>agentCommand</code>의 폴백으로)</li><li><code>assistant</code>: pi-agent-core에서 스트리밍된 델타</li><li><code>tool</code>: pi-agent-core에서 스트리밍된 도구 이벤트</li></ul><h2 id="채팅-채널-처리" tabindex="-1">채팅 채널 처리 <a class="header-anchor" href="#채팅-채널-처리" aria-label="Permalink to &quot;채팅 채널 처리&quot;">​</a></h2><ul><li>어시스턴트 델타는 채팅 <code>delta</code> 메시지로 버퍼링됩니다.</li><li><strong>생명주기 end/error</strong> 시 채팅 <code>final</code>이 방출됩니다.</li></ul><h2 id="타임아웃" tabindex="-1">타임아웃 <a class="header-anchor" href="#타임아웃" aria-label="Permalink to &quot;타임아웃&quot;">​</a></h2><ul><li><code>agent.wait</code> 기본값: 30초 (대기만). <code>timeoutMs</code> 파라미터로 오버라이드 가능합니다.</li><li>에이전트 런타임: <code>agents.defaults.timeoutSeconds</code> 기본값 172800초(48시간); <code>runEmbeddedPiAgent</code> 중단 타이머에서 적용됩니다.</li><li>LLM 유휴 타임아웃: <code>agents.defaults.llm.idleTimeoutSeconds</code>는 유휴 윈도우 이전에 응답 청크가 도착하지 않으면 모델 요청을 중단합니다. 느린 로컬 모델이나 추론/도구 호출 프로바이더에 명시적으로 설정하십시오; 비활성화하려면 0으로 설정하십시오. 설정하지 않으면 OpenClaw는 <code>agents.defaults.timeoutSeconds</code>가 구성된 경우 이를 사용하며, 그렇지 않으면 60초를 사용합니다. 명시적 LLM 또는 에이전트 타임아웃이 없는 크론 트리거 실행은 유휴 감시자를 비활성화하고 크론 외부 타임아웃에 의존합니다.</li></ul><h2 id="조기-종료될-수-있는-위치" tabindex="-1">조기 종료될 수 있는 위치 <a class="header-anchor" href="#조기-종료될-수-있는-위치" aria-label="Permalink to &quot;조기 종료될 수 있는 위치&quot;">​</a></h2><ul><li>에이전트 타임아웃 (중단)</li><li>AbortSignal (취소)</li><li>게이트웨이 연결 해제 또는 RPC 타임아웃</li><li><code>agent.wait</code> 타임아웃 (대기만, 에이전트를 중단하지 않음)</li></ul><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/tools">도구</a> — 사용 가능한 에이전트 도구</li><li><a href="/openclaw-docs-ko/automation/hooks">후크</a> — 에이전트 생명주기 이벤트에 의해 트리거되는 이벤트 기반 스크립트</li><li><a href="/openclaw-docs-ko/concepts/compaction">컴팩션</a> — 긴 대화를 요약하는 방법</li><li><a href="/openclaw-docs-ko/tools/exec-approvals">실행 승인</a> — 셸 명령어에 대한 승인 게이트</li><li><a href="/openclaw-docs-ko/tools/thinking">사고</a> — 사고/추론 수준 구성</li></ul>',43)])])}const g=o(t,[["render",c]]);export{p as __pageData,g as default};
